mapper.select:
select ur.user_id as userId, r.role_name as roleName, r.role_code as roleCode, r.level as roleLevel from osh_user_role ur join osh_role r on r.id = ur.role_id and r.delete_flag = 0 where ur.delete_flag = 0 and ur.user_id in
#{uid}
order by ur.user_id, r.level desc

mapper.insert:
insert into osh_user_role (user_id, role_id, create_time, create_by, update_time, update_by, delete_flag)
values (#{userId}, #{roleId}, now(), #{operatorId}, now(), #{operatorId}, 0)
on duplicate key update delete_flag = 0, update_time = now(), update_by = #{operatorId}
